import os
from xmlschema import validate

def read_and_validate(xmlfile, xsd_file):
    if not os.path.exists(xmlfile) or not os.path.exists(xsd_file):
        print("File doesn't exist.")
        return False
    
    try:
        with open(xsd_file) as schema_file:
            schema = validate(schema_file.read())
        
        with open(xmlfile) as xml_file:
            schema.validate(xml_file.read())
            
        return True
    
    except Exception as e:
        print('Error validating XML file: ', str(e))
        return False